// Parse sync request
const body = $input.first().json.body || $input.first().json;

const validActions = ['sync', 'join', 'leave', 'seek', 'play', 'pause', 'buffer'];
const action = body.action;

if (!validActions.includes(action)) {
  throw new Error('Invalid sync action');
}

return [{
  json: {
    action: action,
    partyId: body.partyId,
    userId: body.userId,
    streamId: body.streamId,
    timestamp: body.timestamp || Date.now(),
    videoTime: body.videoTime || 0,
    playbackRate: body.playbackRate || 1.0,
    bufferHealth: body.bufferHealth || 100,
    clientTime: body.clientTime || Date.now(),
    serverTime: Date.now(),
    syncId: crypto.randomUUID()
  }
}];

// Initialize new master clock
const syncData = $input.first().json;

const masterClock = {
  partyId: syncData.partyId,
  streamId: syncData.streamId,
  masterUserId: syncData.userId,
  startTime: Date.now(),
  videoTime: syncData.videoTime,
  state: 'playing',
  playbackRate: syncData.playbackRate || 1.0,
  lastUpdate: Date.now(),
  participantCount: 1,
  maxDrift: 0,
  syncQuality: 100
};

return [{
  json: {
    ...syncData,
    masterClock: masterClock,
    isNewMaster: true
  }
}];

// Calculate drift and sync offset
const syncData = $input.first().json;
const existingMaster = $input.first().json.existingMaster;

// Parse existing master clock
let masterClock;
try {
  masterClock = typeof existingMaster === 'string' ? JSON.parse(existingMaster) : existingMaster;
} catch (e) {
  masterClock = existingMaster;
}

// Calculate network latency (round-trip time / 2)
const networkLatency = (syncData.serverTime - syncData.clientTime) / 2;

// Calculate client drift from master
const elapsedSinceMasterUpdate = Date.now() - masterClock.lastUpdate;
const expectedVideoTime = masterClock.videoTime + (masterClock.state === 'playing' ? elapsedSinceMasterUpdate / 1000 * masterClock.playbackRate : 0);
const clientVideoTime = syncData.videoTime + (networkLatency / 1000);
const drift = Math.abs(expectedVideoTime - clientVideoTime) * 1000; // in ms

// Update master clock with new stats
masterClock.participantCount = (masterClock.participantCount || 0) + (syncData.action === 'join' ? 1 : syncData.action === 'leave' ? -1 : 0);
masterClock.maxDrift = Math.max(masterClock.maxDrift || 0, drift);
masterClock.lastUpdate = Date.now();

// Calculate sync quality (100 - drift in percentage, capped at 0)
const syncQuality = Math.max(0, 100 - (drift / 10));
masterClock.syncQuality = Math.round((masterClock.syncQuality * 0.9) + (syncQuality * 0.1)); // Moving average

return [{
  json: {
    ...syncData,
    masterClock: masterClock,
    drift: drift,
    networkLatency: networkLatency,
    expectedVideoTime: expectedVideoTime,
    syncOffset: expectedVideoTime - clientVideoTime,
    isNewMaster: false
  }
}];

